	// Keep only safe libraries: base, math, string, table
	L.OpenLibs()

	// Disable dangerous functions
	disableDangerousGlobals(L)

	// Set resource limits using CallByParam with a timeout context
	// Note: gopher-lua doesn't have SetMaster, we use context-based timeout instead
	done := make(chan bool, 1)
	var result float64
	var execErr error

	go func() {
		// Load and execute the script
		if err := L.DoString(script); err != nil {
			execErr = fmt.Errorf("failed to execute Lua script: %w", err)
			done <- false
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			execErr = fmt.Errorf("calculate_final_price is not a function or not defined")
			done <- false
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			execErr = fmt.Errorf("failed to call calculate_final_price: %w", err)
			done <- false
			return
		}

		// Get the result from the Lua stack
		res := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if res.Type() != lua.LTNumber {
			execErr = fmt.Errorf("calculate_final_price did not return a number")
			done <- false
			return
		}

		// Validate the result is a reasonable price (non-negative and not infinite)
		finalPrice := float64(res.(lua.LNumber))
		if finalPrice < 0 {
			execErr = fmt.Errorf("calculate_final_price returned a negative price: %v", finalPrice)
			done <- false
			return
		}

		result = finalPrice
		done <- true
	}()

	// Wait for execution with timeout
	select {
	case <-done:
		if execErr != nil {
			return 0, execErr
		}
		return result, nil
	case <-time.After(5 * time.Second):
		return 0, fmt.Errorf("Lua script execution timeout")
	}
