// disableDangerousGlobals removes access to potentially dangerous Lua functions
// that could be exploited for code injection or system access
func disableDangerousGlobals(L *lua.LState) {
	// Disable os library functions
	L.SetGlobal("os", lua.LNil)

	// Disable io library functions
	L.SetGlobal("io", lua.LNil)

	// Disable debug library
	L.SetGlobal("debug", lua.LNil)

	// Disable load and loadstring which can execute arbitrary code
	L.SetGlobal("load", lua.LNil)
	L.SetGlobal("loadstring", lua.LNil)

	// Disable dofile and require which can load external files
	L.SetGlobal("dofile", lua.LNil)
	L.SetGlobal("require", lua.LNil)
	L.SetGlobal("package", lua.LNil)

	// Disable rawget, rawset, rawlen which bypass metamethods
	L.SetGlobal("rawget", lua.LNil)
	L.SetGlobal("rawset", lua.LNil)
	L.SetGlobal("rawlen", lua.LNil)

	// Disable getmetatable and setmetatable which could be used for exploits
	L.SetGlobal("getmetatable", lua.LNil)
	L.SetGlobal("setmetatable", lua.LNil)
}

